// Normaliza los turnos que vienen del payload de la app
const body = $input.first().json.body || $input.first().json;
const turnos = body.turnos || [];

const results = [];
for (const t of turnos) {
  let cel = (t.celular || '').replace(/\D/g, '');
  if (cel.startsWith('0')) cel = cel.slice(1);
  if (!cel.startsWith('54')) cel = '54' + cel;
  if (cel.startsWith('54') && !cel.startsWith('549')) cel = '549' + cel.slice(2);

  const [y, m, d] = (t.fecha || '').split('-');
  const fechaFmt = `${d}/${m}`;
  const hora = (t.hora || t.hora_inicio || '').substring(0, 5);
  const profApellido = (t.profesional || '').split(',')[0].trim();

  results.push({
    json: {
      turno_id: t.turno_id,
      centro_id: body.centro_id,
      to_whatsapp: 'whatsapp:+' + cel,
      celular_raw: cel,
      content_variables: JSON.stringify({
        '1': t.paciente_nombre || '',
        '2': fechaFmt,
        '3': hora,
        '4': profApellido
      })
    }
  });
}

return results;
